```javascript
function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const teleportList = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => [])
    );
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const INF = Infinity;
    const dist = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => 
            Array(k + 1).fill(INF)
        )
    );
    dist[0][0][0] = 0;

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.siftUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const popped = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.siftDown(0);
            return popped;
        }
        siftUp(index) {
            while (index > 0) {
                const parent = Math.floor((index - 1) / 2);
                if (this.heap[parent][0] <= this.heap[index][0]) break;
                [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
                index = parent;
            }
        }
        siftDown(index) {
            while (index < this.heap.length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
                if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }
        peek() {
            return this.heap[0];
        }
        size() {
            return this.heap.length;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0, 0, 0]);

    while (pq.size() > 0) {
        const [cost, t, i, j] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                pq.push([newCost, t, i, j + 1]);
            }
        }
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                pq.push([newCost, t, i + 1, j]);
            }
        }

        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pq.push([cost, newT, x, y]);
                }
            }
        }
    }

    return dist[m - 1][n - 1][k];
}
