function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    // Precompute teleport list
    const teleportList = Array(m).fill().map(() => Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }
    // Dijkstra's algorithm
    const INF = Infinity;
    const dist = Array(m).fill().map(() => Array(n).fill().map(() => Array(k+1).fill(INF)));
    dist[0][0][0] = 0;
    // Priority queue: min-heap, elements are [cost, t, i, j]
    const heap = [];
    function push(cost, t, i, j) {
        heap.push([cost, t, i, j]);
        let idx = heap.length - 1;
        while (idx > 0) {
            const parent = Math.floor((idx - 1) / 2);
            if (heap[idx][0] < heap[parent][0]) {
                [heap[idx], heap[parent]] = [heap[parent], heap[idx]];
                idx = parent;
            } else {
                break;
            }
        }
    }
    function pop() {
        if (heap.length === 0) return null;
        const min = heap[0];
        heap[0] = heap[heap.length - 1];
        heap.pop();
        // Sift down
        let idx = 0;
        while (true) {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let smallest = idx;
            if (left < heap.length && heap[left][0] < heap[smallest][0]) {
                smallest = left;
            }
            if (right < heap.length && heap[right][0] < heap[smallest][0]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [heap[idx], heap[smallest]] = [heap[smallest], heap[idx]];
            idx = smallest;
        }
        return min;
    }
    // Dijkstra's loop
    push(0, 0, 0, 0);
    while (heap.length > 0) {
        const [cost, t, i, j] = pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }
        // Regular moves: right and down
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                push(newCost, t, i, j + 1);
            }
        }
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                push(newCost, t, i + 1, j);
            }
